css:
* {
  box-sizing: border-box !important;
}

html, body {
  min-height: 100vh !important;
  background: #08080f !important;
  color: #c0d0d0 !important;
  font-family: 'Courier New', 'Consolas', 'Menlo', monospace !important;
}

body::before {
  content: '' !important;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: -1 !important;
  background: 
    radial-gradient(circle at 30% 20%, rgba(0, 255, 136, 0.03) 0%, transparent 50%),
    radial-gradient(circle at 70% 80%, rgba(0, 204, 255, 0.03) 0%, transparent 50%),
    linear-gradient(180deg, #08080f 0%, #0a0a18 100%);
  background-blend-mode: overlay !important;
}

/* ===== CANVAS ДЛЯ МАТРИЦЫ И КОДА ===== */
#codewave-canvas {
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: 1 !important;
  pointer-events: none !important;
  background: transparent !important;
}

.p-pageWrapper,
.p-body,
.p-body-inner,
.p-body-main,
.p-body-content,
.p-body-pageContent,
.p-body-header,
.pageContent,
.p-body-inner {
  background: transparent !important;
}

.p-body-inner {
  background: rgba(8, 8, 15, 0.8) !important;
  backdrop-filter: blur(12px) !important;
  -webkit-backdrop-filter: blur(12px) !important;
  border-radius: 16px !important;
  padding: 24px !important;
  box-shadow: 0 0 60px rgba(0, 255, 136, 0.04), inset 0 0 60px rgba(0, 255, 136, 0.02), 0 0 0 1px rgba(0, 255, 136, 0.08) !important;
  border: none !important;
  margin: 16px auto !important;
  position: relative;
  z-index: 3;
  overflow: hidden;
}

.p-body-inner::after {
  content: '>_' !important;
  position: absolute !important;
  bottom: 8px !important;
  right: 16px !important;
  font-size: 12px !important;
  color: rgba(0, 255, 136, 0.15) !important;
  font-family: 'Courier New', monospace !important;
  letter-spacing: 2px !important;
  pointer-events: none !important;
  z-index: 0 !important;
  animation: cursorBlink 1s step-end infinite !important;
}

@keyframes cursorBlink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

.p-body-inner::before {
  content: '' !important;
  position: absolute !important;
  top: -2px !important;
  left: -2px !important;
  right: -2px !important;
  bottom: -2px !important;
  border-radius: 18px !important;
  background: 
    linear-gradient(135deg, rgba(0, 255, 136, 0.06), transparent 40%, transparent 60%, rgba(0, 204, 255, 0.06)) !important;
  z-index: -1 !important;
  pointer-events: none !important;
}

.p-header {
  background: rgba(8, 8, 15, 0.7) !important;
  backdrop-filter: blur(8px) !important;
  border-bottom: 1px solid rgba(0, 255, 136, 0.08) !important;
  border-radius: 16px 16px 0 0 !important;
  padding: 12px 24px !important;
  box-shadow: 0 4px 30px rgba(0,0,0,0.6) !important;
}

.p-header-logo a {
  color: #00ff88 !important;
  font-weight: 700 !important;
  letter-spacing: 1px !important;
  text-shadow: 0 0 30px rgba(0, 255, 136, 0.2) !important;
  font-family: 'Courier New', 'Consolas', monospace !important;
  font-size: 1.4em !important;
}

.p-header-logo a::before {
  content: '> ' !important;
  color: #00ccff !important;
}

.p-header-logo a::after {
  content: ' _' !important;
  color: #00ccff !important;
  animation: cursorBlink 1s step-end infinite !important;
}

.p-header-logo a:hover {
  text-shadow: 0 0 60px rgba(0, 255, 136, 0.4) !important;
}

.p-nav {
  background: rgba(8, 8, 15, 0.8) !important;
  backdrop-filter: blur(12px) !important;
  border-bottom: 1px solid rgba(0, 255, 136, 0.06) !important;
  box-shadow: 0 4px 32px rgba(0,0,0,0.7) !important;
  padding: 0 16px !important;
}

.p-nav-inner {
  background: transparent !important;
}

.p-nav-list {
  display: flex !important;
  gap: 4px !important;
  background: transparent !important;
}

.p-nav-list .p-navEl {
  color: #90b0b0 !important;
  font-weight: 500 !important;
  padding: 12px 20px !important;
  border-radius: 8px !important;
  transition: all 0.3s ease !important;
  background: transparent !important;
  font-family: 'Courier New', 'Consolas', monospace !important;
  position: relative;
  font-size: 0.85em !important;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.p-nav-list .p-navEl::before {
  content: '[' !important;
  color: rgba(0, 255, 136, 0) !important;
  transition: all 0.3s ease !important;
}

.p-nav-list .p-navEl::after {
  content: ']' !important;
  color: rgba(0, 255, 136, 0) !important;
  transition: all 0.3s ease !important;
}

.p-nav-list .p-navEl:hover::before,
.p-nav-list .p-navEl:hover::after {
  color: rgba(0, 255, 136, 0.5) !important;
}

.p-nav-list .p-navEl:hover {
  background: rgba(0, 255, 136, 0.06) !important;
  color: #b0e0d0 !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 0 30px rgba(0, 255, 136, 0.04) !important;
  text-shadow: 0 0 20px rgba(0, 255, 136, 0.08) !important;
}

.p-nav-list .p-navEl.is-selected {
  background: rgba(0, 255, 136, 0.08) !important;
  color: #00ff88 !important;
  box-shadow: inset 0 0 0 1px rgba(0, 255, 136, 0.1) !important;
  text-shadow: 0 0 20px rgba(0, 255, 136, 0.1) !important;
}

.p-nav-list .p-navEl.is-selected::before,
.p-nav-list .p-navEl.is-selected::after {
  color: rgba(0, 255, 136, 0.6) !important;
}

.p-nav-opposite {
  background: transparent !important;
}

.p-navgroup {
  background: transparent !important;
}

.p-navgroup-link {
  color: #90b0b0 !important;
  transition: all 0.2s !important;
  font-family: 'Courier New', monospace !important;
}

.p-navgroup-link:hover {
  color: #00ff88 !important;
  background: rgba(0, 255, 136, 0.06) !important;
  border-radius: 8px !important;
  text-shadow: 0 0 20px rgba(0, 255, 136, 0.08) !important;
}

/* Блоки — окна терминала */
.block {
  background: rgba(8, 8, 15, 0.6) !important;
  backdrop-filter: blur(8px) !important;
  -webkit-backdrop-filter: blur(8px) !important;
  border-radius: 12px !important;
  border: 1px solid rgba(0, 255, 136, 0.06) !important;
  box-shadow: 0 4px 24px rgba(0,0,0,0.6), inset 0 0 60px rgba(0, 255, 136, 0.02) !important;
  padding: 20px !important;
  margin-bottom: 24px !important;
  transition: all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94) !important;
  position: relative;
  overflow: hidden;
}

.block::before {
  content: '' !important;
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  height: 2px !important;
  background: linear-gradient(90deg, transparent, rgba(0, 255, 136, 0.2), transparent) !important;
  pointer-events: none !important;
  z-index: 0 !important;
}

.block::after {
  content: '/* */' !important;
  position: absolute !important;
  top: 8px !important;
  right: 12px !important;
  font-size: 10px !important;
  color: rgba(0, 255, 136, 0.06) !important;
  font-family: 'Courier New', monospace !important;
  pointer-events: none !important;
}

.block:hover {
  box-shadow: 0 8px 40px rgba(0,0,0,0.8), inset 0 0 60px rgba(0, 255, 136, 0.04) !important;
  transform: translateY(-2px) !important;
  border-color: rgba(0, 255, 136, 0.12) !important;
}

.block-container {
  background: transparent !important;
  border: none !important;
}

.block-body {
  background: transparent !important;
}

.block-minorHeader {
  color: #00ff88 !important;
  font-weight: 600 !important;
  padding: 12px 16px !important;
  border-bottom: 1px solid rgba(0, 255, 136, 0.06) !important;
  text-shadow: 0 0 20px rgba(0, 255, 136, 0.08) !important;
  font-family: 'Courier New', 'Consolas', monospace !important;
  letter-spacing: 0.5px;
  font-size: 0.9em !important;
}

.block-minorHeader::before {
  content: '// ' !important;
  color: rgba(0, 204, 255, 0.3) !important;
}

.node {
  background: rgba(10, 10, 20, 0.4) !important;
  border-radius: 12px !important;
  border: 1px solid rgba(0, 255, 136, 0.04) !important;
  padding: 16px 20px !important;
  margin-bottom: 8px !important;
  transition: all 0.3s ease !important;
  position: relative;
}

.node:hover {
  background: rgba(14, 14, 28, 0.6) !important;
  border-color: rgba(0, 255, 136, 0.1) !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 8px 30px rgba(0,0,0,0.5) !important;
}

.node-title a {
  color: #c0d0d0 !important;
  font-weight: 600 !important;
  text-shadow: 0 0 10px rgba(0, 255, 136, 0.04) !important;
}

.node-title a:hover {
  color: #00ff88 !important;
  text-shadow: 0 0 30px rgba(0, 255, 136, 0.15) !important;
}

.node-stats {
  color: #809898 !important;
}

.node-extra {
  color: #809898 !important;
}

.node-extra-title {
  color: #90b0b0 !important;
}

.node-extra-title:hover {
  color: #00ff88 !important;
}

.uix_newIndicator {
  background: rgba(0, 255, 136, 0.1) !important;
  color: #00ff88 !important;
  border-radius: 4px !important;
  padding: 2px 12px !important;
  font-size: 10px !important;
  text-shadow: 0 0 10px rgba(0, 255, 136, 0.15) !important;
  font-family: 'Courier New', monospace !important;
}

.node-body {
  background: transparent !important;
  display: flex !important;
  align-items: center !important;
  flex-wrap: wrap !important;
  gap: 8px !important;
}

.structItem {
  background: rgba(8, 8, 18, 0.35) !important;
  border-radius: 12px !important;
  border: 1px solid rgba(0, 255, 136, 0.03) !important;
  padding: 12px 16px !important;
  margin-bottom: 6px !important;
  transition: all 0.25s ease !important;
  display: flex !important;
  align-items: stretch !important;
  flex-wrap: nowrap !important;
  gap: 12px !important;
}

.structItem:hover {
  background: rgba(12, 12, 24, 0.5) !important;
  border-color: rgba(0, 255, 136, 0.08) !important;
  box-shadow: 0 4px 20px rgba(0,0,0,0.4) !important;
}

.structItem-cell {
  display: flex !important;
  align-items: center !important;
}

.structItem-cell--icon {
  flex: 0 0 48px !important;
  min-width: 48px !important;
  justify-content: center !important;
}

.structItem-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  flex-direction: column !important;
  align-items: stretch !important;
}

.structItem-cell--meta {
  flex: 0 0 100px !important;
  justify-content: center !important;
  align-items: flex-start !important;
}

.structItem-cell--latest {
  flex: 0 0 120px !important;
  justify-content: center !important;
  align-items: flex-end !important;
  text-align: right !important;
}

.structItem-cell--iconEnd {
  flex: 0 0 32px !important;
  justify-content: center !important;
}

.structItem-title {
  color: #c0d0d0 !important;
  font-weight: 500 !important;
}

.structItem-title a {
  color: #c0d0d0 !important;
}

.structItem-title a:hover {
  color: #00ff88 !important;
  text-shadow: 0 0 30px rgba(0, 255, 136, 0.12) !important;
}

.structItem-statuses {
  color: #809898 !important;
  display: flex !important;
  gap: 4px !important;
  align-items: center !important;
}

.structItem-status--locked {
  color: #ff8888 !important;
}

.structItem-status--sticky {
  color: #f0c080 !important;
}

.structItem-minor {
  color: #708888 !important;
  font-size: 12px !important;
}

.structItem-minor a {
  color: #809898 !important;
}

.structItem-minor a:hover {
  color: #00ff88 !important;
}

.structItem-parts {
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  margin: 0 !important;
  padding: 0 !important;
  list-style: none !important;
}

.structItem-parts li {
  display: inline !important;
}

.structItem-latestDate {
  color: #809898 !important;
}

.structItem--quickCreate {
  background: rgba(8, 8, 18, 0.25) !important;
  border: 1px dashed rgba(0, 255, 136, 0.08) !important;
  border-radius: 12px !important;
}

.structItem--quickCreate textarea {
  background: rgba(6, 6, 14, 0.5) !important;
  border: 1px solid rgba(0, 255, 136, 0.06) !important;
  color: #c0d0d0 !important;
  border-radius: 12px !important;
  padding: 12px !important;
  font-family: 'Courier New', monospace !important;
}

.structItem--quickCreate textarea:focus {
  border-color: rgba(0, 255, 136, 0.25) !important;
  box-shadow: 0 0 0 4px rgba(0, 255, 136, 0.04) !important;
}

.message {
  background: rgba(10, 10, 20, 0.45) !important;
  backdrop-filter: blur(6px) !important;
  -webkit-backdrop-filter: blur(6px) !important;
  border-radius: 12px !important;
  border: 1px solid rgba(0, 255, 136, 0.04) !important;
  padding: 0 !important;
  margin-bottom: 20px !important;
  transition: all 0.3s ease !important;
  overflow: hidden !important;
  position: relative;
}

.message:hover {
  background: rgba(14, 14, 28, 0.55) !important;
  border-color: rgba(0, 255, 136, 0.1) !important;
  box-shadow: 0 8px 32px rgba(0,0,0,0.6) !important;
  transform: translateY(-2px) !important;
}

.message-inner {
  background: transparent !important;
  display: flex !important;
  flex-wrap: wrap !important;
}

.message-cell {
  background: transparent !important;
  padding: 16px !important;
}

.message-cell--user {
  background: rgba(6, 6, 14, 0.25) !important;
  border-right: 1px solid rgba(0, 255, 136, 0.04) !important;
  border-radius: 12px 0 0 12px !important;
  min-width: 180px !important;
  flex: 0 0 180px !important;
}

.message-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  border-radius: 0 12px 12px 0 !important;
}

.message-user {
  background: transparent !important;
}

.message-avatar {
  text-align: center !important;
  margin-bottom: 8px !important;
}

.message-avatar .avatar {
  border-radius: 50% !important;
  border: 2px solid rgba(0, 255, 136, 0.15) !important;
  transition: all 0.3s ease !important;
  box-shadow: 0 0 20px rgba(0, 255, 136, 0.04) !important;
}

.message-avatar .avatar:hover {
  transform: scale(1.08) !important;
  border-color: rgba(0, 255, 136, 0.3) !important;
  box-shadow: 0 0 40px rgba(0, 255, 136, 0.1) !important;
}

.message-userDetails {
  text-align: center !important;
}

.message-name {
  font-weight: 600 !important;
  font-size: 14px !important;
  font-family: 'Courier New', 'Consolas', monospace !important;
}

.message-name a {
  color: #c0d0d0 !important;
}

.message-name a:hover {
  color: #00ff88 !important;
  text-shadow: 0 0 30px rgba(0, 255, 136, 0.15) !important;
}

.userBanner {
  background: rgba(0, 255, 136, 0.06) !important;
  border-radius: 4px !important;
  padding: 2px 14px !important;
  font-size: 10px !important;
  color: #809898 !important;
  display: inline-block !important;
  margin-top: 4px !important;
  text-shadow: 0 0 10px rgba(0, 255, 136, 0.04) !important;
  font-family: 'Courier New', monospace !important;
}

.userBanner--red {
  background: rgba(200, 80, 80, 0.1) !important;
  color: #ff8888 !important;
}

.userBanner--primary {
  background: rgba(0, 204, 255, 0.06) !important;
  color: #809898 !important;
}

.message-userExtras {
  margin-top: 8px !important;
  font-size: 11px !important;
  color: #708888 !important;
  font-family: 'Courier New', monospace !important;
}

.message-userExtras .pairs {
  padding: 2px 0 !important;
}

.message-userExtras .pairs dt {
  color: #506868 !important;
}

.message-userExtras .pairs dd {
  color: #809898 !important;
}

.message-attribution {
  background: rgba(6, 6, 14, 0.15) !important;
  padding: 8px 16px !important;
  border-bottom: 1px solid rgba(0, 255, 136, 0.03) !important;
}

.message-attribution a {
  color: #708888 !important;
}

.message-attribution a:hover {
  color: #00ff88 !important;
}

.message-newIndicator {
  background: rgba(0, 255, 136, 0.08) !important;
  color: #00ff88 !important;
  border-radius: 4px !important;
  padding: 2px 12px !important;
  font-size: 10px !important;
  text-shadow: 0 0 10px rgba(0, 255, 136, 0.15) !important;
  font-family: 'Courier New', monospace !important;
}

.message-content {
  padding: 16px !important;
}

.message-body {
  color: #c0d0d0 !important;
  font-size: 14px !important;
  line-height: 1.7 !important;
}

.message-body .bbWrapper {
  color: #c0d0d0 !important;
}

.message-body a {
  color: #00ccff !important;
}

.message-body a:hover {
  color: #00ff88 !important;
  text-shadow: 0 0 30px rgba(0, 255, 136, 0.15) !important;
}

.message-body .bbMediaWrapper {
  border-radius: 12px !important;
  overflow: hidden !important;
  background: rgba(6, 6, 14, 0.5) !important;
  border: 1px solid rgba(0, 255, 136, 0.06) !important;
}

.message-body .bbMediaWrapper iframe {
  border-radius: 12px !important;
}

.message-fields--before {
  background: rgba(8, 8, 18, 0.25) !important;
  border-radius: 12px !important;
  padding: 12px 16px !important;
  margin-bottom: 12px !important;
  border: 1px solid rgba(0, 255, 136, 0.04) !important;
}

.message-fields--before .pairs {
  padding: 2px 0 !important;
}

.message-fields--before .pairs dt {
  color: #506868 !important;
  font-weight: 500 !important;
}

.message-fields--before .pairs dd {
  color: #809898 !important;
}

.message-signature {
  background: rgba(6, 6, 14, 0.12) !important;
  border-top: 1px solid rgba(0, 255, 136, 0.03) !important;
  padding: 12px 16px !important;
  margin-top: 12px !important;
  border-radius: 0 0 12px 12px !important;
  font-size: 12px !important;
  color: #708888 !important;
  max-height: 100px !important;
  overflow: hidden !important;
  transition: max-height 0.3s ease !important;
  font-family: 'Courier New', monospace !important;
}

.message-signature--expanded {
  max-height: 500px !important;
}

.message-signature .bbWrapper {
  color: #708888 !important;
}

.message-signature a {
  color: #608888 !important;
}

.message-signature a:hover {
  color: #00ff88 !important;
}

.uix_signatureExpand {
  cursor: pointer !important;
  color: #506868 !important;
  font-size: 10px !important;
  text-align: center !important;
  padding: 4px !important;
  border-radius: 4px !important;
  background: rgba(0, 255, 136, 0.03) !important;
  margin-bottom: 6px !important;
  transition: all 0.2s !important;
  font-family: 'Courier New', monospace !important;
}

.uix_signatureExpand:hover {
  background: rgba(0, 255, 136, 0.06) !important;
  color: #00ff88 !important;
}

.actionBar {
  background: rgba(6, 6, 14, 0.15) !important;
  border-top: 1px solid rgba(0, 255, 136, 0.03) !important;
  padding: 6px 16px !important;
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  border-radius: 0 0 12px 12px !important;
}

.actionBar-action {
  background: transparent !important;
  color: #708888 !important;
  padding: 4px 12px !important;
  border-radius: 4px !important;
  font-size: 12px !important;
  transition: all 0.2s !important;
  cursor: pointer !important;
  font-family: 'Courier New', monospace !important;
}

.actionBar-action:hover {
  background: rgba(0, 255, 136, 0.06) !important;
  color: #00ff88 !important;
}

.actionBar-action--reaction {
  background: rgba(0, 255, 136, 0.03) !important;
}

.actionBar-action--reaction:hover {
  background: rgba(0, 255, 136, 0.08) !important;
}

.actionBar-action--menuTrigger {
  color: #506868 !important;
}

.actionBar-action--menuTrigger:hover {
  background: rgba(0, 255, 136, 0.04) !important;
}

.blockStatus {
  background: rgba(8, 8, 18, 0.5) !important;
  border-radius: 8px !important;
  border: 1px solid rgba(0, 255, 136, 0.06) !important;
  padding: 8px 24px !important;
  color: #809898 !important;
  backdrop-filter: blur(4px) !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 8px !important;
  font-family: 'Courier New', monospace !important;
}

.blockStatus-message {
  color: #809898 !important;
}

.blockStatus-message--locked {
  border-color: #cc6666 !important;
  color: #ff8888 !important;
  background: rgba(200, 80, 80, 0.06) !important;
  border-radius: 4px !important;
  padding: 4px 16px !important;
}

.message-newIndicator,
.uix_newIndicator {
  background: rgba(0, 255, 136, 0.08) !important;
  color: #00ff88 !important;
  border-radius: 4px !important;
  padding: 2px 12px !important;
  font-size: 10px !important;
  font-weight: 600 !important;
  text-shadow: 0 0 10px rgba(0, 255, 136, 0.15) !important;
  font-family: 'Courier New', monospace !important;
}

.message--deleted {
  opacity: 0.5 !important;
  background: rgba(200, 80, 80, 0.04) !important;
  border-color: rgba(200, 80, 80, 0.06) !important;
}

.messageNotice--deleted {
