(function() {
  // ===== CODYWAVE — ХАКЕРСКАЯ ТЕМА С МАТРИЦЕЙ И КОДОМ =====
  function initCodeWave() {
    const canvas = document.createElement('canvas');
    canvas.id = 'codewave-canvas';
    canvas.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;z-index:1;pointer-events:none;background:transparent;';
    document.body.appendChild(canvas);

    const ctx = canvas.getContext('2d');
    let W, H;
    let time = 0;

    function resize() {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
    }
    window.addEventListener('resize', resize);
    resize();

    // ===== МАТРИЧНЫЙ ДОЖДЬ (символы) =====
    const chars = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz!@#$%^&*()_+-=[]{}|;:,.<>?/';
    const columns = Math.floor(W / 20);
    const drops = [];
    for (let i = 0; i < columns; i++) {
      drops.push({
        x: i * 20 + 10,
        y: Math.random() * H,
        speed: 0.5 + Math.random() * 1.5,
        length: 5 + Math.random() * 20,
        chars: []
      });
      // Генерируем символы для каждой колонки
      for (let j = 0; j < drops[i].length; j++) {
        drops[i].chars.push(chars[Math.floor(Math.random() * chars.length)]);
      }
    }

    // ===== АНИМИРОВАННЫЕ СТРОКИ КОДА =====
    const codeSnippets = [
      'function init() {',
      'const data = await fetch();',
      'for (let i = 0; i < 10; i++) {',
      'console.log("Hello World");',
      'return response.json();',
      'const result = data.map(x => x * 2);',
      'await new Promise(resolve => setTimeout(resolve, 1000));',
      'if (error) { throw new Error("Failed"); }',
      'const config = { env: "production" };',
      'export default component;'
    ];
    let codeLines = [];
    for (let i = 0; i < 8; i++) {
      codeLines.push({
        text: codeSnippets[Math.floor(Math.random() * codeSnippets.length)],
        x: Math.random() * W * 0.8 + 20,
        y: 40 + i * 28,
        opacity: 0.05 + Math.random() * 0.08,
        speed: 0.3 + Math.random() * 0.5,
        phase: Math.random() * Math.PI * 2
      });
    }

    // ===== НЕОНОВЫЕ ЛИНИИ (сетка) =====
    function drawGrid() {
      ctx.strokeStyle = 'rgba(0, 255, 136, 0.02)';
      ctx.lineWidth = 0.5;
      for (let x = 0; x < W; x += 40) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, H);
        ctx.stroke();
      }
      for (let y = 0; y < H; y += 40) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(W, y);
        ctx.stroke();
      }
    }

    function drawMatrixRain() {
      for (const drop of drops) {
        drop.y += drop.speed;
        if (drop.y > H + drop.length * 16) {
          drop.y = -drop.length * 16;
          for (let j = 0; j < drop.length; j++) {
            drop.chars[j] = chars[Math.floor(Math.random() * chars.length)];
          }
        }
        for (let j = 0; j < drop.length; j++) {
          const yPos = drop.y - j * 16;
          if (yPos < 0 || yPos > H) continue;
          const alpha = 1 - (j / drop.length);
          const color = j === 0
            ? `rgba(0, 255, 136, ${0.6 + Math.random() * 0.4})`
            : `rgba(0, 255, 136, ${alpha * 0.15})`;
          ctx.fillStyle = color;
          ctx.font = '14px monospace';
          ctx.shadowColor = 'rgba(0, 255, 136, 0.1)';
          ctx.shadowBlur = 5;
          ctx.fillText(drop.chars[j], drop.x, yPos);
          ctx.shadowBlur = 0;
        }
      }
    }

    function drawCodeLines() {
      for (const line of codeLines) {
        line.y += line.speed * 0.3;
        if (line.y > H + 20) {
          line.y = -20;
          line.x = Math.random() * W * 0.8 + 20;
          line.text = codeSnippets[Math.floor(Math.random() * codeSnippets.length)];
          line.opacity = 0.05 + Math.random() * 0.08;
        }
        const alpha = line.opacity * (0.7 + 0.3 * Math.sin(time * 0.005 + line.phase));
        ctx.fillStyle = `rgba(0, 204, 255, ${alpha})`;
        ctx.font = '12px monospace';
        ctx.shadowColor = 'rgba(0, 204, 255, 0.05)';
        ctx.shadowBlur = 10;
        ctx.fillText(line.text, line.x, line.y);
        ctx.shadowBlur = 0;
      }
    }

    // ===== СВЕТЯЩИЕСЯ ТОЧКИ (как звёзды) =====
    const stars = [];
    for (let i = 0; i < 50; i++) {
      stars.push({
        x: Math.random() * W,
        y: Math.random() * H,
        size: 0.5 + Math.random() * 1.5,
        phase: Math.random() * Math.PI * 2,
        speed: 0.01 + Math.random() * 0.02
      });
    }

    function drawStars() {
      for (const star of stars) {
        const alpha = 0.3 + 0.7 * Math.sin(time * star.speed + star.phase);
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(0, 255, 136, ${alpha * 0.1})`;
        ctx.shadowColor = 'rgba(0, 255, 136, 0.05)';
        ctx.shadowBlur = 5;
        ctx.fill();
        ctx.shadowBlur = 0;
      }
    }

    function draw() {
      time++;
      ctx.clearRect(0, 0, W, H);

      drawGrid();
      drawStars();
      drawMatrixRain();
      drawCodeLines();

      requestAnimationFrame(draw);
    }

    draw();
  }

  initCodeWave();
  console.log('[CodeWave] Хакерская тема с матрицей и кодом активирована.');
})();
